/**
 * 자동 기간별 일지 생성 서비스 (주간/월간/연간)
 *
 * ─────────────────────────────────────────────
 * 트리거: 배치 생성 시 (auto/manual 모두)
 *  → 일일일지: autoGenerateDailyReport (별도 파일)
 *  → 주간일지: 해당 주 첫 배치 → autoGenerateWeeklyLog
 *  → 월간일지: 해당 월 첫 배치 → autoGenerateMonthlyLog
 *  → 연간일지: 연간 첫 작성일 기준 → autoGenerateYearlyLog
 *
 * 데이터 저장:
 *  → h_generic_checklist_records 테이블 (form_type으로 구분)
 *  → 프론트엔드 WeeklyLogForm / MonthlyLogForm 양식과 동일한 구조
 *
 * 문서결재설정 연동:
 *  → h_document_approval_settings에서 검토자/승인자 조회
 *  → h_approval_requests 생성 시 설정값 반영
 *
 * 휴무 관리 (h_holidays) 연동:
 *  → 주간/월간 "첫 배치"는 h_holidays를 제외한 첫 영업일 배치
 *  → 이미 해당 기간에 일지가 있으면 skip
 * ─────────────────────────────────────────────
 */

import { getDb, getRawConnection } from "../db";
import { sql } from "drizzle-orm";

export interface PeriodicLogResult {
  success: boolean;
  logType: "weekly" | "monthly" | "yearly";
  recordId: number | null;
  approvalRequestId: number | null;
  isNew: boolean;
  message: string;
}

// ============================================================================
// 문서결재설정 조회 헬퍼
// ============================================================================

interface ApprovalSetting {
  authorEmployeeId: number | null;
  reviewerEmployeeId: number | null;
  approverEmployeeId: number | null;
}

async function getApprovalSettingForType(
  tenantId: number,
  documentType: string
): Promise<ApprovalSetting> {
  try {
    const db = await getDb();
    if (!db) return { authorEmployeeId: null, reviewerEmployeeId: null, approverEmployeeId: null };

    const result = await db.execute(sql`
      SELECT author_employee_id, reviewer_employee_id, approver_employee_id
      FROM h_document_approval_settings
      WHERE document_type = ${documentType}
        AND tenant_id = ${tenantId}
        AND is_active = 1
      LIMIT 1
    `);
    const rows = (result as any)[0] || [];
    if (rows.length === 0) {
      return { authorEmployeeId: null, reviewerEmployeeId: null, approverEmployeeId: null };
    }
    return {
      authorEmployeeId: rows[0].author_employee_id ? Number(rows[0].author_employee_id) : null,
      reviewerEmployeeId: rows[0].reviewer_employee_id ? Number(rows[0].reviewer_employee_id) : null,
      approverEmployeeId: rows[0].approver_employee_id ? Number(rows[0].approver_employee_id) : null,
    };
  } catch (err) {
    console.error(`[autoPeriodicLogs] 문서결재설정 조회 실패 (${documentType}):`, err);
    return { authorEmployeeId: null, reviewerEmployeeId: null, approverEmployeeId: null };
  }
}

