// ============================================================================
// 주간일지 자동 생성
// ============================================================================

/**
 * 해당 주의 첫 배치인지 확인 후 주간일지 자동 생성
 * - h_generic_checklist_records (form_type='weekly_log') 기반
 * - WeeklyLogForm.tsx 양식과 동일한 form_data 구조
 * - h_document_approval_settings 연동
 */
export async function autoGenerateWeeklyLog(
  tenantId: number,
  siteId: number,
  workDate: string,
  userId: number,
  batchInfo?: { batchId: number; productName: string; plannedQty: number }
): Promise<PeriodicLogResult> {
  const db = await getDb();
  if (!db) return { success: false, logType: "weekly", recordId: null, approvalRequestId: null, isNew: false, message: "DB 연결 실패" };

  try {
    // 1. 해당 주의 월~일 범위 계산
    const { weekStart, weekEnd } = getWeekRange(workDate);

    // 2. 이미 해당 주에 주간일지가 있으면 skip (h_generic_checklist_records 기준)
    const existingResult = await db.execute(sql`
      SELECT id FROM h_generic_checklist_records
      WHERE form_type = 'weekly_log'
        AND tenant_id = ${tenantId}
        AND form_date BETWEEN ${weekStart} AND ${weekEnd}
      LIMIT 1
    `);
    const existingRows = (existingResult as any)[0] || [];
    if (existingRows.length > 0) {
      return {
        success: true, logType: "weekly",
        recordId: existingRows[0].id,
        approvalRequestId: null, isNew: false,
        message: `주간일지 이미 존재 (ID: ${existingRows[0].id})`,
      };
    }

    // 3. 해당 주에 이전 배치가 있었는지 확인 (현재가 첫 배치인지)
    const conn = await getRawConnection();
    const isFirst = await isFirstBatchOfPeriod(conn, tenantId, weekStart, workDate);
    if (!isFirst) {
      return {
        success: true, logType: "weekly",
        recordId: null, approvalRequestId: null, isNew: false,
        message: `이번 주 첫 배치가 아니므로 주간일지 미생성`,
      };
    }

    // 4. 문서결재설정 조회
    const approvalSetting = await getApprovalSettingForType(tenantId, 'weekly_log');

    // 5. 주간일지 생성 (h_generic_checklist_records)
    const formData = buildDefaultWeeklyFormData(workDate, batchInfo);

    const seqResult = await db.execute(sql`
      SELECT COALESCE(MAX(tenant_seq), 0) + 1 as next_seq
      FROM h_generic_checklist_records
      WHERE form_type = 'weekly_log'
        AND tenant_id = ${tenantId}
        AND YEAR(created_at) = YEAR(NOW())
    `);
    const nextSeq = Number((seqResult as any)[0]?.[0]?.next_seq || 1);

    const title = `주간일지 - ${weekStart} ~ ${weekEnd}`;
    const createdBy = approvalSetting.authorEmployeeId || userId;

    const insertResult = await db.execute(sql`
      INSERT INTO h_generic_checklist_records
        (site_id, tenant_id, form_type, tenant_seq, form_date, title, form_data, status, created_by)
      VALUES
        (${siteId}, ${tenantId}, 'weekly_log', ${nextSeq}, ${workDate}, ${title},
         ${JSON.stringify(formData)}, 'draft', ${createdBy})
    `);
    const recordId = Number((insertResult as any)[0]?.insertId || 0);

    // 6. 승인요청 등록 (h_approval_requests)
    const approvalTitle = `[주간일지] ${weekStart} ~ ${weekEnd} 주간 위생점검`;
    const approvalDesc =
      `점검기간: ${weekStart} ~ ${weekEnd}\n` +
      `점검일: ${workDate}\n` +
      (approvalSetting.reviewerEmployeeId ? `검토자 ID: ${approvalSetting.reviewerEmployeeId}\n` : '') +
      (approvalSetting.approverEmployeeId ? `승인자 ID: ${approvalSetting.approverEmployeeId}\n` : '') +
      `[자동생성 - 위생점검 항목을 작성해주세요]`;

    const approvalInsert = await db.execute(sql`
      INSERT INTO h_approval_requests
        (site_id, tenant_id, request_type, reference_type, reference_id,
         title, description, status, priority, requested_by, created_at)
      VALUES
        (${siteId}, ${tenantId}, 'weekly_log', 'checklist', ${recordId},
         ${approvalTitle}, ${approvalDesc}, 'pending_review', 'medium', ${createdBy}, NOW())
    `);
    const approvalRequestId = Number((approvalInsert as any)[0]?.insertId || 0);

    console.log(`[autoPeriodicLogs] 주간일지 생성: #${recordId}, 승인요청: #${approvalRequestId}`);

    return {
      success: true, logType: "weekly",
      recordId, approvalRequestId, isNew: true,
      message: `주간일지 자동 생성 완료 (#${recordId})`,
    };
  } catch (error: any) {
    console.error("[autoPeriodicLogs] 주간일지 생성 실패:", error);
    return {
      success: false, logType: "weekly",
      recordId: null, approvalRequestId: null, isNew: false,
      message: error.message || "주간일지 생성 실패",
    };
  }
}

// ============================================================================
// 월간일지 자동 생성
